:root {
  --brand-dark: #1a2e4a;
  --brand-mid: #2d5282;
  --brand-accent: #e07b39;
  --brand-accent-dark: #c4612a;
  --bg-card: #ffffff;
  --bg-header: #1a2e4a;
  --bg-detail: #f0f4f9;
  --bg-amenity: #e8f0fb;
  --rating-bg: #e07b39;
  --tag-bg: #e07b39;
  --tag-text: #ffffff;
  --text-primary: #1a2e4a;
  --text-secondary: #5a7396;
  --text-light: #ffffff;
  --text-muted: #8aa0b8;
  --original-price-color: #8aa0b8;
  --final-price-color: #e07b39;
  --border-color: #dde6f0;
  --btn-bg: #e07b39;
  --btn-text: #ffffff;
  --btn-hover: #c4612a;
}

.booking-card {
  background: var(--bg-card);
  border-radius: 16px;
  border: 1px solid var(--border-color);
  width: 500px;
  overflow: hidden;
  margin: 0 auto;
}

.card-header {
  background: var(--bg-header);
  padding: 16px 20px;
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
}

.hotel-info {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.hotel-tag {
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1px;
  padding: 2px 8px;
  border-radius: 4px;
  width: fit-content;
}

.hotel-name {
  color: var(--text-light);
  font-size: 20px;
  font-weight: 700;
  margin: 0;
  line-height: 1.2;
}

.hotel-location {
  color: var(--text-muted);
  font-size: 13px;
  margin: 0;
}

.rating-box {
  background: var(--rating-bg);
  border-radius: 10px;
  padding: 8px 12px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.rating-score {
  color: var(--text-light);
  font-size: 22px;
  font-weight: 800;
  line-height: 1;
}

.rating-label {
  color: var(--text-light);
  font-size: 10px;
  font-weight: 600;
}

.room-details {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1px;
  background: var(--border-color);
  border-bottom: 1px solid var(--border-color);
}

.detail-item {
  background: var(--bg-detail);
  padding: 12px 14px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.detail-label {
  color: var(--text-secondary);
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.detail-value {
  color: var(--text-primary);
  font-size: 13px;
  font-weight: 700;
}

.amenities {
  display: flex;
  gap: 8px;
  padding: 12px 20px;
  border-bottom: 1px solid var(--border-color);
  flex-wrap: wrap;
}

.amenity {
  background: var(--bg-amenity);
  color: var(--brand-mid);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
}

.card-footer {
  padding: 14px 20px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.price-section {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.price-nights {
  color: var(--text-secondary);
  font-size: 12px;
  font-weight: 500;
}

.price-row {
  display: flex;
  align-items: baseline;
  gap: 8px;
}

.original-price {
  color: var(--original-price-color);
  font-size: 14px;
  font-weight: 500;
  text-decoration: line-through;
}

.final-price {
  color: var(--final-price-color);
  font-size: 28px;
  font-weight: 800;
  line-height: 1;
}

.price-note {
  color: var(--text-muted);
  font-size: 11px;
}

.book-btn {
  background: var(--btn-bg);
  color: var(--btn-text);
  border: none;
  border-radius: 10px;
  padding: 14px 28px;
  font-size: 15px;
  font-weight: 700;
  cursor: pointer;
}
